protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexes are managed via the container's indexing policy,
    // not EF Core. EF Core 9 throws if HasIndex is used with Cosmos.

    // Preserve "Discriminator" property name for compatibility with existing documents
    // (EF Core 9 defaults to "$type").
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve "Blog|1" id format for compatibility with existing documents
    // (EF Core 9 defaults to key-only ids).
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

